using System;
using System.IO;

public class CPHInline
{
    private const string DOSSIER_JOUEURS = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\joueurs";

    public bool Execute()
    {
        string nomJoueur     = args["user"].ToString();
        string cheminFichier = Path.Combine(DOSSIER_JOUEURS, nomJoueur.ToLower() + ".json");

        if (!File.Exists(cheminFichier))
        {
            CPH.SendMessage(nomJoueur + ", tape !rejoindre pour créer ton profil !");
            return true;
        }

        string json = File.ReadAllText(cheminFichier);

        // Message 1 : identité
        int niveau = int.Parse(LireValeur(json, "niveau"));
        int xp     = int.Parse(LireValeur(json, "experience"));
        int ram    = int.Parse(LireValeur(json, "ram"));
        CPH.SendMessage(nomJoueur + " | Niv " + niveau + " | XP : " + xp + " | RAM : " + ram);

        // Message 2 : classe
        if (LireValeur(json, "classeChoisie") != "true")
        {
            CPH.SendMessage(nomJoueur + " — Classe : aucune (tape !choisirclasse)");
        }
        else
        {
            string classe     = LireValeur(json, "classe");
            string sousClasse = LireValeur(json, "sousClasse");
            string typeArme   = LireValeur(json, "typeArme");
            string msg2 = nomJoueur + " — Classe : " + classe;
            if (sousClasse != "" && sousClasse != "0") msg2 += " / " + sousClasse;
            msg2 += " | Arme : " + (typeArme != "" && typeArme != "0" ? typeArme : "aucune");
            CPH.SendMessage(msg2);
        }

        // Message 3 : stats combat
        int pvActuels  = int.Parse(LireValeur(json, "pvActuels"));
        int pvMax      = int.Parse(LireValeur(json, "pvMax"));
        int ca         = int.Parse(LireValeur(json, "classeArmure"));
        int atq        = int.Parse(LireValeur(json, "bonusAttaque"));
        int manaActuels = int.Parse(LireValeur(json, "manaActuels"));
        int manaMax    = int.Parse(LireValeur(json, "manaMax"));
        int charisme   = int.Parse(LireValeur(json, "charisme"));

        string msg3 = nomJoueur + " — PV : " + pvActuels + "/" + pvMax + " | CA : " + ca + " | Atq : +" + atq;
        if (manaMax > 0) msg3 += " | Mana : " + manaActuels + "/" + manaMax;
        if (charisme > 0) msg3 += " | Charisme : " + charisme;
        CPH.SendMessage(msg3);

        // Message 4 : stats + items équipés
        int combatsGagnes   = int.Parse(LireValeur(json, "combatsGagnes"));
        int combatsPerdus   = int.Parse(LireValeur(json, "combatsPerdus"));
        int quetesTerminees = int.Parse(LireValeur(json, "quetesTerminees"));
        bool enCombat = LireValeur(json, "enCombat") == "true";
        bool enQuete  = LireValeur(json, "enQuete")  == "true";

        string msg4 = nomJoueur + " — Combats : " + combatsGagnes + "V/" + combatsPerdus + "D | Quêtes : " + quetesTerminees;
        if (enCombat) msg4 += " | EN COMBAT";
        else if (enQuete) msg4 += " | EN QUETE";

        string armeEq   = LireValeur(json, "armeEquipee");
        string armureEq = LireValeur(json, "armureEquipee");
        string accEq    = LireValeur(json, "accessoireEquipe");
        string equipe   = "";
        if (armeEq   != "" && armeEq   != "0") equipe += " Arme:" + armeEq;
        if (armureEq != "" && armureEq != "0") equipe += " Armure:" + armureEq;
        if (accEq    != "" && accEq    != "0") equipe += " Acc:" + accEq;
        if (equipe   != "") msg4 += " |" + equipe;

        CPH.SendMessage(msg4);
        return true;
    }

    private string LireValeur(string json, string cle)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut    = json.IndexOf(marqueur);
        if (posDebut == -1) return "0";
        posDebut       += marqueur.Length;
        int posFin      = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        return json.Substring(posDebut, posFin - posDebut).Trim().Trim('"');
    }
}

using System;
using System.IO;

public class CPHInline
{
    private const string DOSSIER_JOUEURS = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\joueurs";
    private const string CONFIG_CLASSES  = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\config_classes.json";

    public bool Execute()
    {
        // ── Nom du viewer et classe tapée ─────────────────────
        // rawInput = ce que le joueur a écrit après la commande
        // Ex : "!choisirclasse Cryptolame" → rawInput = "cryptolame"
        string nomJoueur     = args["user"].ToString();
        string rawInput      = args["rawInput"].ToString().Trim().ToLower();
        string cheminFichier = Path.Combine(DOSSIER_JOUEURS, nomJoueur.ToLower() + ".json");

        // ── Vérifications ─────────────────────────────────────
        if (!File.Exists(cheminFichier))
        {
            CPH.SendMessage(nomJoueur + ", tape !rejoindre d'abord !");
            return true;
        }

        string json            = File.ReadAllText(cheminFichier);
        bool classeDejaChoisie = LireValeur(json, "classeChoisie") == "true";

        if (classeDejaChoisie)
        {
            CPH.SendMessage(nomJoueur + ", tu as déjà une classe ! " +
                "Rencontre un Marchand de Classe pour en changer.");
            return true;
        }

        // ── Normalisation du nom de classe ────────────────────
        string classeNom;
        switch (rawInput)
        {
            case "hexadécimeur":
            case "hexadecimeur":    classeNom = "Hexadécimeur";    break;
            case "cryptolame":      classeNom = "Cryptolame";      break;
            case "hackmancien":     classeNom = "Hackmancien";     break;
            case "firewaller":      classeNom = "Firewaller";      break;
            case "algorythmancien": classeNom = "Algorythmancien"; break;
            default:
                CPH.SendMessage(nomJoueur + ", classe inconnue ! Choisis parmi : " +
                    "Hexadécimeur · Cryptolame · Hackmancien · Firewaller · Algorythmancien");
                return true;
        }

        // ── Chargement des stats depuis la config ─────────────
        string cfg       = File.ReadAllText(CONFIG_CLASSES);
        int pvBase       = int.Parse(LireValeur(cfg, classeNom + "_pvBase"));
        int caBase       = int.Parse(LireValeur(cfg, classeNom + "_caBase"));
        int manaBase     = int.Parse(LireValeur(cfg, classeNom + "_manaBase"));
        int charismeBase = int.Parse(LireValeur(cfg, classeNom + "_charisme"));
        string typeArme  = LireValeur(cfg, classeNom + "_typeArme");

        // ── Jets de dés ───────────────────────────────────────
        Random rng = new Random();

        int jetPV        = rng.Next(1, 7);  // 1d6 → 1 à 6
        int jetCA        = rng.Next(1, 5);  // 1d4 → 1 à 4
        int bonusAttaque = rng.Next(1, 5);  // 1d4 → 1 à 4

        int pvFinal  = pvBase  + jetPV;
        int caFinale = caBase  + jetCA;

        // ── Sauvegarde dans le JSON ───────────────────────────
        json = ModifierValeur(json, "classeChoisie", "true",                  false);
        json = ModifierValeur(json, "classe",         classeNom,              true);
        json = ModifierValeur(json, "typeArme",       typeArme,               true);
        json = ModifierValeur(json, "pvMax",          pvFinal.ToString(),     false);
        json = ModifierValeur(json, "pvActuels",      pvFinal.ToString(),     false);
        json = ModifierValeur(json, "classeArmure",   caFinale.ToString(),    false);
        json = ModifierValeur(json, "bonusAttaque",   bonusAttaque.ToString(),false);
        json = ModifierValeur(json, "manaMax",        manaBase.ToString(),    false);
        json = ModifierValeur(json, "manaActuels",    manaBase.ToString(),    false);
        json = ModifierValeur(json, "charisme",       charismeBase.ToString(),false);

        File.WriteAllText(cheminFichier, json);

        // ── Message dans le chat ──────────────────────────────
        // On formate le signe du bonus pour afficher +2 ou -1
        string signCA  = jetCA        >= 0 ? "+" + jetCA        : jetCA.ToString();
        string signAtq = bonusAttaque >= 0 ? "+" + bonusAttaque : bonusAttaque.ToString();

        CPH.SendMessage(nomJoueur + " entre dans l'Antre en tant que " + classeNom + " ! " +
            "PV : " + pvBase + "+" + jetPV + "=" + pvFinal + " | " +
            "CA : " + caBase + signCA + "=" + caFinale + " | " +
            "Atq : " + signAtq + " | " +
            "Arme : " + typeArme);

        return true;
    }

    // ── LireValeur ────────────────────────────────────────────
    private string LireValeur(string json, string cle)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut    = json.IndexOf(marqueur);
        if (posDebut == -1) return "";
        posDebut       += marqueur.Length;
        int posFin      = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        return json.Substring(posDebut, posFin - posDebut).Trim().Trim('"');
    }

    // ── ModifierValeur ────────────────────────────────────────
    // estTexte = true  → entoure la valeur de guillemets  "Cryptolame"
    // estTexte = false → écrit la valeur brute             16, true, false
    private string ModifierValeur(string json, string cle, string nouvelleValeur, bool estTexte)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut    = json.IndexOf(marqueur);
        if (posDebut == -1) return json;
        posDebut       += marqueur.Length;
        int posFin      = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        string ancienne = json.Substring(posDebut, posFin - posDebut);
        string nouvelle = estTexte ? "\"" + nouvelleValeur + "\"" : nouvelleValeur;
        return json.Substring(0, posDebut) + nouvelle + json.Substring(posDebut + ancienne.Length);
    }
}

using System;
using System.IO;

public class CPHInline
{
    private const string DOSSIER_JOUEURS = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\joueurs";
    private const string CONFIG_CLASSES  = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\config_classes.json";

    public bool Execute()
    {
        string nomJoueur = args["user"].ToString();
        string cheminFichier = Path.Combine(DOSSIER_JOUEURS, $"{nomJoueur}.json");

        if (!File.Exists(cheminFichier))
        {
            CPH.SendMessage(nomJoueur + ", tu n'es pas encore inscrit ! Tape !rejoindre.");
            return true;
        }

        string json = File.ReadAllText(cheminFichier);

        if (LireValeur(json, "classeChoisie") != "true")
        {
            CPH.SendMessage(nomJoueur + ", tu n'as pas encore choisi de classe ! Tape !choisirclasse.");
            return true;
        }

        if (LireValeur(json, "sousClasseChoisie") == "true")
        {
            string sousClasseActuelle = LireValeur(json, "sousClasse");
            CPH.SendMessage(nomJoueur + ", tu as déjà choisi ta sous-classe : " + sousClasseActuelle + " !");
            return true;
        }

        int niveau = int.Parse(LireValeur(json, "niveau"));
        if (niveau < 5)
        {
            CPH.SendMessage(nomJoueur + ", il te faut atteindre le niveau 5 pour choisir une sous-classe ! (Tu es niveau " + niveau + ")");
            return true;
        }

        string classe = LireValeur(json, "classe");
        string rawInput = args.ContainsKey("rawInput") ? args["rawInput"].ToString().Trim() : "";

        if (string.IsNullOrEmpty(rawInput))
        {
            CPH.SendMessage(nomJoueur + ", choisis ta sous-classe : " + GetOptionsSousClasse(classe) + " → Tape !choisirSousClasse [nom]");
            return true;
        }

        string sousClasse = NormaliserSousClasse(rawInput);

        if (string.IsNullOrEmpty(sousClasse))
        {
            CPH.SendMessage(nomJoueur + ", sous-classe inconnue. Options pour " + classe + " : " + GetOptionsSousClasse(classe));
            return true;
        }

        if (!SousClasseValide(classe, sousClasse))
        {
            CPH.SendMessage(nomJoueur + ", cette sous-classe n'est pas disponible pour la classe " + classe + ". Options : " + GetOptionsSousClasse(classe));
            return true;
        }

        string msgBonus = AppliquerBonusSousClasse(ref json, sousClasse);

        json = ModifierValeur(json, "sousClasse", sousClasse, true);
        json = ModifierValeur(json, "sousClasseChoisie", "true", false);

        File.WriteAllText(cheminFichier, json);
        CPH.SendMessage(nomJoueur + " choisit la sous-classe " + sousClasse + " ! " + msgBonus);
        return true;
    }

    private string AppliquerBonusSousClasse(ref string json, string sousClasse)
    {
        string cfg   = File.ReadAllText(CONFIG_CLASSES);
        int pvBonus  = int.Parse(LireValeur(cfg, sousClasse + "_pvMaxBonus"));
        int caModif  = int.Parse(LireValeur(cfg, sousClasse + "_caModif"));
        string arme  = LireValeur(cfg, sousClasse + "_typeArme");

        if (pvBonus != 0)
        {
            json = AjouterValeur(json, "pvMax", pvBonus);
            json = AjouterValeur(json, "pvActuels", pvBonus);
        }
        if (caModif != 0)
            json = AjouterValeur(json, "classeArmure", caModif);
        if (arme != "0" && arme != "")
            json = ModifierValeur(json, "typeArme", arme, true);

        switch (sousClasse)
        {
            case "Bloc-Hex":        return "+" + pvBonus + " PV max — tu es un monolithe de métal !";
            case "Surcharge":       return caModif + " CA, 2 attaques par tour — attaque sans retenue !";
            case "Byte-Fantôme":    return "3 attaques par tour — frappe comme une ombre !";
            case "Pointeur-Null":   return "Arme → " + arme + ", 1d10 dégâts — vise juste !";
            case "Faille-Zéro":     return "2d8 dégâts — tu exploites la faille ultime du système !";
            case "Compilateur":     return "Buff un allié +2 attaque — assemble la force collective !";
            case "Protocole-Sacré": return "Aura protectrice pour tes alliés — sois leur rempart !";
            case "Serment-Binaire": return "Smite +1d8 en combat — jure sur le code !";
            case "Barde-Binaire":   return "1d10 dégâts et buff TOUS les alliés — la musique du réseau !";
            case "Patch-Mélodique": return "Soin 1d8+3 — ta fréquence corrige toutes les blessures !";
            default:                return "";
        }
    }

    private bool SousClasseValide(string classe, string sousClasse)
    {
        switch (classe)
        {
            case "Hexadécimeur":    return sousClasse == "Bloc-Hex"         || sousClasse == "Surcharge";
            case "Cryptolame":      return sousClasse == "Byte-Fantôme"     || sousClasse == "Pointeur-Null";
            case "Hackmancien":     return sousClasse == "Faille-Zéro"      || sousClasse == "Compilateur";
            case "Firewaller":      return sousClasse == "Protocole-Sacré"  || sousClasse == "Serment-Binaire";
            case "Algorythmancien": return sousClasse == "Barde-Binaire"    || sousClasse == "Patch-Mélodique";
            default:                return false;
        }
    }

    private string GetOptionsSousClasse(string classe)
    {
        switch (classe)
        {
            case "Hexadécimeur":    return "Bloc-Hex (+8 PV) · Surcharge (2 attaques/-2 CA)";
            case "Cryptolame":      return "Byte-Fantôme (3 attaques) · Pointeur-Null (1d10/Arc)";
            case "Hackmancien":     return "Faille-Zéro (1d12) · Compilateur (buff allié)";
            case "Firewaller":      return "Protocole-Sacré (aura) · Serment-Binaire (Smite +1d8)";
            case "Algorythmancien": return "Barde-Binaire (1d10/buff tous) · Patch-Mélodique (soin 1d8+3)";
            default:                return "aucune option disponible";
        }
    }

    private string NormaliserSousClasse(string input)
    {
        switch (input.ToLower().Trim())
        {
            case "bloc-hex":
            case "blochex":              return "Bloc-Hex";
            case "surcharge":            return "Surcharge";
            case "byte-fantôme":
            case "byte-fantome":         return "Byte-Fantôme";
            case "pointeur-null":        return "Pointeur-Null";
            case "faille-zéro":
            case "faille-zero":          return "Faille-Zéro";
            case "compilateur":          return "Compilateur";
            case "protocole-sacré":
            case "protocole-sacre":      return "Protocole-Sacré";
            case "serment-binaire":      return "Serment-Binaire";
            case "barde-binaire":        return "Barde-Binaire";
            case "patch-mélodique":
            case "patch-melodique":      return "Patch-Mélodique";
            default:                     return "";
        }
    }

    private string LireValeur(string json, string cle)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut = json.IndexOf(marqueur);
        if (posDebut == -1) return "0";
        posDebut += marqueur.Length;
        int posFin = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        return json.Substring(posDebut, posFin - posDebut).Trim().Trim('"');
    }

    private string ModifierValeur(string json, string cle, string val, bool estTexte)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut = json.IndexOf(marqueur);
        if (posDebut == -1) return json;
        posDebut += marqueur.Length;
        int posFin = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        string ancienne = json.Substring(posDebut, posFin - posDebut);
        string nouvelle = estTexte ? "\"" + val + "\"" : val;
        return json.Substring(0, posDebut) + nouvelle + json.Substring(posDebut + ancienne.Length);
    }

    private string AjouterValeur(string json, string cle, int montant)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut = json.IndexOf(marqueur);
        if (posDebut == -1) return json;
        posDebut += marqueur.Length;
        int posFin = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        string ancienneStr = json.Substring(posDebut, posFin - posDebut).Trim().Trim('"');
        int ancienne = int.TryParse(ancienneStr, out int v) ? v : 0;
        return json.Substring(0, posDebut) + (ancienne + montant).ToString() + json.Substring(posDebut + (posFin - posDebut));
    }
}

using System;
using System.IO;

public class CPHInline
{
    private const string DOSSIER_JOUEURS = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\joueurs";
    private const string CONFIG_GLOBAL   = @"C:\Users\Florian\pjt\Pointu-PJT\Donnees\config_global.json";

    public bool Execute()
    {
        string nomJoueur     = args["user"].ToString();
        string cheminFichier = Path.Combine(DOSSIER_JOUEURS, nomJoueur.ToLower() + ".json");

        if (!File.Exists(cheminFichier))
        {
            CPH.SendMessage(nomJoueur + ", tu n'es pas encore inscrit ! Tape !rejoindre.");
            return true;
        }

        string json = File.ReadAllText(cheminFichier);

        if (LireValeur(json, "classeChoisie") != "true")
        {
            CPH.SendMessage(nomJoueur + ", choisis d'abord une classe avec !choisirclasse !");
            return true;
        }

        if (LireValeur(json, "enCombat") == "true")
        {
            CPH.SendMessage(nomJoueur + ", tu ne peux pas te reposer en plein combat !");
            return true;
        }

        if (LireValeur(json, "enQuete") == "true")
        {
            CPH.SendMessage(nomJoueur + ", tu es en pleine quête — pas le temps de se reposer !");
            return true;
        }

        if (int.Parse(LireValeur(json, "pvActuels")) <= 0)
        {
            CPH.SendMessage(nomJoueur + ", tu récupères de ta défaite dans l'Antre de Pointu — impossible de te soigner maintenant !");
            return true;
        }

        long maintenant  = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
        long cooldownFin = long.Parse(LireValeur(json, "reposCooldownFin"));

        if (maintenant < cooldownFin)
        {
            long restant  = cooldownFin - maintenant;
            int  minutes  = (int)(restant / 60);
            int  secondes = (int)(restant % 60);
            CPH.SendMessage(nomJoueur + ", l'Antre de Pointu se recharge... encore " + minutes + "m " + secondes + "s avant de pouvoir te reposer.");
            return true;
        }

        int pvActuels   = int.Parse(LireValeur(json, "pvActuels"));
        int pvMax       = int.Parse(LireValeur(json, "pvMax"));
        int manaActuels = int.Parse(LireValeur(json, "manaActuels"));
        int manaMax     = int.Parse(LireValeur(json, "manaMax"));

        int pvRestores   = pvMax   - pvActuels;
        int manaRestores = manaMax - manaActuels;

        json = EnsureChamp(json, "reposCooldownFin", "0", false);
        json = ModifierValeur(json, "pvActuels",        pvMax.ToString(),                false);
        json = ModifierValeur(json, "manaActuels",      manaMax.ToString(),              false);
        int reposCooldown = int.Parse(LireValeur(File.ReadAllText(CONFIG_GLOBAL), "repos_cooldown_secondes"));
        json = ModifierValeur(json, "reposCooldownFin", (maintenant + reposCooldown).ToString(), false);

        File.WriteAllText(cheminFichier, json);

        string msgPV   = pvRestores   > 0 ? "+" + pvRestores   + " PV"   : "PV déjà au max";
        string msgMana = manaRestores > 0 ? " · +" + manaRestores + " mana" : "";
        int reposMins = reposCooldown / 60;
        CPH.SendMessage(nomJoueur + " se repose dans l'Antre de Pointu. La carapace ancienne pulse doucement... " + msgPV + msgMana + " ! (Prochain repos dans " + reposMins + " min)");

        return true;
    }

    // Insère un champ s'il est absent du JSON (pour les anciens profils)
    private string EnsureChamp(string json, string cle, string valeurDefaut, bool estTexte)
    {
        if (json.Contains("\"" + cle + "\"")) return json;
        int    pos = json.LastIndexOf('}');
        string val = estTexte ? "\"" + valeurDefaut + "\"" : valeurDefaut;
        return json.Substring(0, pos) + ",\n  \"" + cle + "\": " + val + "\n}";
    }

    private string LireValeur(string json, string cle)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut    = json.IndexOf(marqueur);
        if (posDebut == -1) return "0";
        posDebut       += marqueur.Length;
        int posFin      = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        return json.Substring(posDebut, posFin - posDebut).Trim().Trim('"');
    }

    private string ModifierValeur(string json, string cle, string val, bool estTexte)
    {
        string marqueur = "\"" + cle + "\": ";
        int posDebut    = json.IndexOf(marqueur);
        if (posDebut == -1) return json;
        posDebut       += marqueur.Length;
        int posFin      = json.IndexOfAny(new char[] { ',', '\n', '}' }, posDebut);
        string ancienne = json.Substring(posDebut, posFin - posDebut);
        string nouvelle = estTexte ? "\"" + val + "\"" : val;
        return json.Substring(0, posDebut) + nouvelle + json.Substring(posDebut + ancienne.Length);
    }
}

